import sys

def main():
    sys.stdout.reconfigure(encoding='utf-8')
    chapters_dir = r"d:\bharatheeyam books\assets\data\chapters"

    # Common English words transliterated into Kannada script
    english_kannada_patterns = [
        " ಥೇ ", " ಅಂದ್ ", " ಓಫ಼್ ", " ತೋ ", " ಇಸ್ ", " ಠಿಸ್ ", " ಅರೇ ", " ವೀ ", " ಅಸ್ ", " ಬ್ಯ್ ", " ಫ಼ೋರ್ ", " ಫ಼್ರೋಂ ", " ಏತ್ ", " cಏತೇರ ", " ಹುಮನ್ ", " ಬೋದ್ಯ್ ", " ಥತ್ ", " ಂಏಅನಿನ್ಗ್ ", " ಇನ್ಗ್ಲಿಶ್ ", " ಒಬೇಇಸನ್cಏಸ್ "
    ]

    suspicious_files = {}

    for filename in os.listdir(chapters_dir):
        if not filename.endswith(".txt"):
            continue
        filepath = os.path.join(chapters_dir, filename)
        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()

        found = []
        for pat in english_kannada_patterns:
            if pat in content:
                found.append(pat.strip())

        if found:
            suspicious_files[filename] = found

    print(f"Found {len(suspicious_files)} suspicious files:")
    for fn, pats in sorted(suspicious_files.items()):
        print(f"{fn}: {pats}")

if __name__ == '__main__':
    main()
