"import json

def main():
    index_path = r"d:\bharatheeyam books\assets\data\scriptures_index.json"
    with open(index_path, 'r', encoding='utf-8') as f:
        data = json.load(f)

    for item in data:
        title = item.get('titleEn', item.get('title', ''))
        if 'Brihadaranyaka' in title or 'ಬೃಹದಾರಣ್ಯಕ' in title:
            print(f"Title: {title}")
            print(f"Category: {item.get('category')}")
            for ch in item.get('chapters', []):
                print(f"  Chapter ID: {ch.get('id')}, Title: {ch.get('title')}")

if __name__ == '__main__':
    main()
"

"import sys

def main():
    sys.stdout.reconfigure(encoding='utf-8')
    path1 = r"d:\bharatheeyam books\assets\data\chapters\upanishad_brinew-proofed_ch_1.txt"
    path2 = r"d:\bharatheeyam books\assets\data\chapters\upanishad_bri_ch_1.txt"

    print("=== upanishad_brinew-proofed_ch_1.txt headings ===")
    with open(path1, 'r', encoding='utf-8') as f:
        for idx, line in enumerate(f):
            if any(h in line for h in ["ಬ್ರಾಹ್ಮಣ", "ಅಧ್ಯಾಯ", "ಮಂತ್ರ", "ಸಮಾಪ್ತ"]):
                if idx < 500 or "ಅಧ್ಯಾಯ" in line: # print first 500 lines' headings and all Adhyaya headings
                    print(f"Line {idx+1}: {line.strip()}")

    print("\n=== upanishad_bri_ch_1.txt headings ===")
    with open(path2, 'r', encoding='utf-8') as f:
        for idx, line in enumerate(f):
            if any(h in line for h in ["ಬ್ರಾಹ್ಮಣ", "ಅಧ್ಯಾಯ", "ಮಂತ್ರ", "{ಚ್"]):
                if idx < 500 or "{ಚ್" in line:
                    print(f"Line {idx+1}: {line.strip()}")

if __name__ == '__main__':
    main()
"

