"import os
import sys

def main():
    sys.stdout.reconfigure(encoding='utf-8')
    chapters_dir = r"d:\bharatheeyam books\assets\data\chapters"

    permitted_chars = {
        '•': 0x2022,
        '–': 0x2013,
        '—': 0x2014,
        '\xa0': 0xa0,
        '\u200c': 0x200c,
        '\u200d': 0x200d,
        '\u2018': 0x2018,
        '\u2019': 0x2019,
        '\u201c': 0x201c,
        '\u201d': 0x201d,
    }

    bad_chars_found = {}

    for ch_num in range(66, 99):
        filename = f"upanishad_paramatmikopanishat_ch_{ch_num}.txt"
        filepath = os.path.join(chapters_dir, filename)
        if not os.path.exists(filepath):
            continue

        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()

        file_bad_chars = []
        for idx, char in enumerate(content):
            o = ord(char)
            is_permitted = (
                (0x0c80 <= o <= 0x0cff) or 
                (0x0964 <= o <= 0x0965) or 
                (0 <= o <= 127) or 
                (char in permitted_chars)
            )
            if not is_permitted:
                start = max(0, idx - 15)
                end = min(len(content), idx + 15)
                context = content[start:end].replace('\n', ' ')
                file_bad_chars.append((idx, char, hex(o), context))

        if file_bad_chars:
            bad_chars_found[filename] = file_bad_chars

    if bad_chars_found:
        print(f"Detected bad characters in {len(bad_chars_found)} files:")
        for fname, bads in sorted(bad_chars_found.items()):
            print(f"\nFile: {fname}")
            for idx, char, hx, ctx in bads:
                print(f"  Position {idx}: character '{char}' ({hx}) in context: ... {ctx} ...")
    else:
        print("All Batch 26 files are 100% clean of foreign characters!")

if __name__ == '__main__':
    main()
"

